import{_ as o,o as i,c as l,ag as a}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"เกี่ยวกับ Dotfiles | Dotfiles (TH)","titleTemplate":":title","description":"สำรวจภาพรวมทางเทคนิคของ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","frontmatter":{"title":"เกี่ยวกับ Dotfiles | Dotfiles","description":"สำรวจภาพรวมทางเทคนิคของ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","lang":"th-TH","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"เกี่ยวกับ Dotfiles | Dotfiles preview","canonical":"/th/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"เกี่ยวกับ Dotfiles","pageType":"docs","schemaType":"WebPage","permalink":"/th/about/"},"headers":[],"relativePath":"th/about/index.md","filePath":"th/about/index.md","lastUpdated":1773010926000}'),d={name:"th/about/index.md"};function t(c,e,s,h,r,n){return i(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="เกี่ยวกับ-dotfiles" tabindex="-1">เกี่ยวกับ Dotfiles <a class="header-anchor" href="#เกี่ยวกับ-dotfiles" aria-label="Permalink to &quot;เกี่ยวกับ Dotfiles&quot;">​</a></h1><p>Dotfiles v0.2.495 คือการกำหนดค่าเชลล์ข้ามแพลตฟอร์มที่จัดการโดย Chezmoi</p><h2 id="ติดตั้ง" tabindex="-1">ติดตั้ง <a class="header-anchor" href="#ติดตั้ง" aria-label="Permalink to &quot;ติดตั้ง&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="ตรวจสอบ" tabindex="-1">ตรวจสอบ <a class="header-anchor" href="#ตรวจสอบ" aria-label="Permalink to &quot;ตรวจสอบ&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="คําสั่งหลัก" tabindex="-1">คำสั่งหลัก <a class="header-anchor" href="#คําสั่งหลัก" aria-label="Permalink to &quot;คำสั่งหลัก&quot;">​</a></h2><ul><li><code>dot apply</code> ใช้การเปลี่ยนแปลงการกำหนดค่า</li><li><code>dot update</code> อัปเดตรีโพและอุ่นแคช</li><li><code>dot doctor</code> ตรวจสอบพาธ เครื่องมือ และสุขภาพเชลล์</li><li><code>dot heal</code> ซ่อมแซมสถานะที่หายไปหรือเสียหาย</li><li><code>dot smoke-test</code> ตรวจสอบ toolchain หลัก</li></ul><h2 id="ที่เกี่ยวข้อง" tabindex="-1">ที่เกี่ยวข้อง <a class="header-anchor" href="#ที่เกี่ยวข้อง" aria-label="Permalink to &quot;ที่เกี่ยวข้อง&quot;">​</a></h2><ul><li><a href="/th/aliases/">นามแฝง</a></li><li><a href="/th/functions/">ฟังก์ชัน</a></li><li><a href="/th/paths/">พาธ</a></li></ul><h2 id="คําสั่งหลัก-1" tabindex="-1">คำสั่งหลัก <a class="header-anchor" href="#คําสั่งหลัก-1" aria-label="Permalink to &quot;คำสั่งหลัก&quot;">​</a></h2><p>CLI <code>dot</code> มี 53 คำสั่งจัดตามหมวดหมู่</p><h3 id="แกนหลัก" tabindex="-1">แกนหลัก <a class="header-anchor" href="#แกนหลัก" aria-label="Permalink to &quot;แกนหลัก&quot;">​</a></h3><ul><li><code>dot apply</code> — ใช้การเปลี่ยนแปลงการกำหนดค่า.</li><li><code>dot sync</code> — ดึงสถานะ repo ล่าสุดและใช้งาน.</li><li><code>dot update</code> — อัปเดต repo และอุ่นแคช.</li><li><code>dot add</code> — เพิ่มไฟล์ใหม่ลงในแหล่ง Chezmoi.</li><li><code>dot diff</code> — แสดงการเปลี่ยนแปลงที่รอดำเนินการก่อนใช้งาน.</li><li><code>dot status</code> — แสดงสถานะไฟล์ที่จัดการ.</li><li><code>dot remove</code> — ยกเลิกการจัดการไฟล์และลบรายการแหล่ง.</li><li><code>dot cd</code> — เปิด Shell ในไดเรกทอรีแหล่ง Chezmoi.</li><li><code>dot edit</code> — เปิดไฟล์ที่จัดการในโปรแกรมแก้ไข.</li><li><code>dot clean-cache</code> — ล้างแคชชั่วคราว.</li><li><code>dot prewarm</code> — เติมแคชล่วงหน้าเพื่อเริ่ม Shell เร็วขึ้น.</li></ul><h3 id="การวินิจฉัย" tabindex="-1">การวินิจฉัย <a class="header-anchor" href="#การวินิจฉัย" aria-label="Permalink to &quot;การวินิจฉัย&quot;">​</a></h3><ul><li><code>dot doctor</code> — ตรวจสอบเส้นทาง เครื่องมือ และสถานะ Shell.</li><li><code>dot heal</code> — ซ่อมแซมสถานะที่ขาดหายหรือเสียหายโดยอัตโนมัติ.</li><li><code>dot health</code> — รันการตรวจสอบสุขภาพแบบเบา.</li><li><code>dot verify</code> — ตรวจสอบความสมบูรณ์ของไฟล์เทียบกับแหล่ง.</li><li><code>dot scorecard</code> — แสดงคะแนนคุณภาพการกำหนดค่า.</li><li><code>dot snapshot</code> — บันทึกสถานะปัจจุบันเพื่อเปรียบเทียบในภายหลัง.</li><li><code>dot smoke-test</code> — ตรวจสอบ toolchain หลักแบบครบวงจร.</li><li><code>dot chaos</code> — ใส่ข้อผิดพลาดเพื่อทดสอบการซ่อมแซมตัวเอง.</li><li><code>dot bundle</code> — ส่งออกชุดการกำหนดค่าแบบพกพา.</li><li><code>dot rollback</code> — ย้อนกลับไปยัง snapshot ก่อนหน้า.</li><li><code>dot drift</code> — ตรวจจับการเปลี่ยนแปลงที่ไม่คาดคิดในไฟล์ที่จัดการ.</li><li><code>dot history</code> — แสดงบันทึกประวัติ apply/sync.</li><li><code>dot benchmark</code> — วัดเวลาเริ่มต้น Shell.</li><li><code>dot perf</code> — วิเคราะห์การเริ่มต้น Shell ที่ช้า.</li></ul><h3 id="ลักษณะที่ปรากฏ" tabindex="-1">ลักษณะที่ปรากฏ <a class="header-anchor" href="#ลักษณะที่ปรากฏ" aria-label="Permalink to &quot;ลักษณะที่ปรากฏ&quot;">​</a></h3><ul><li><code>dot theme</code> — เปลี่ยนชุดสีของเทอร์มินัล.</li><li><code>dot wallpaper</code> — ตั้งวอลเปเปอร์เดสก์ท็อป (macOS).</li><li><code>dot fonts</code> — ติดตั้งหรืออัปเดต Nerd Fonts.</li><li><code>dot tune</code> — ปรับความหนาแน่น UI และสไตล์ prompt.</li></ul><h3 id="ความปลอดภัย" tabindex="-1">ความปลอดภัย <a class="header-anchor" href="#ความปลอดภัย" aria-label="Permalink to &quot;ความปลอดภัย&quot;">​</a></h3><ul><li><code>dot backup</code> — สร้างการสำรองข้อมูลการกำหนดค่าที่เข้ารหัส.</li><li><code>dot encrypt-check</code> — ตรวจสอบการเข้ารหัสข้อมูลลับในขณะพัก.</li><li><code>dot firewall</code> — กำหนดค่ากฎไฟร์วอลล์ของโฮสต์.</li><li><code>dot telemetry</code> — ควบคุมการวัดผลการใช้งานแบบไม่ระบุตัวตน.</li><li><code>dot dns-doh</code> — เปิดใช้งาน DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — ล็อกหน้าจอทันที.</li><li><code>dot usb-safety</code> — จำกัดการเมาท์อัตโนมัติของ USB mass-storage.</li></ul><h3 id="ข้อมูลลับ" tabindex="-1">ข้อมูลลับ <a class="header-anchor" href="#ข้อมูลลับ" aria-label="Permalink to &quot;ข้อมูลลับ&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — เริ่มต้นแบ็กเอนด์ข้อมูลลับ (age / GPG).</li><li><code>dot secrets</code> — แสดงรายการข้อมูลลับที่เข้ารหัส.</li><li><code>dot secrets-create</code> — สร้างข้อมูลลับที่เข้ารหัสใหม่.</li><li><code>dot ssh-key</code> — สร้างหรือหมุนเวียนคู่กุญแจ SSH.</li><li><code>dot ssh-cert</code> — ขอใบรับรอง SSH จาก CA.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — เปิดเซสชันผู้ช่วย AI แบบโต้ตอบ.</li><li><code>dot ai-setup</code> — กำหนดค่าคีย์ API สำหรับผู้ให้บริการ AI.</li><li><code>dot ai-query</code> — ส่ง prompt ครั้งเดียวไปยังโมเดล AI.</li><li>ตัวครอบ AI tool: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="เครื่องมือ" tabindex="-1">เครื่องมือ <a class="header-anchor" href="#เครื่องมือ" aria-label="Permalink to &quot;เครื่องมือ&quot;">​</a></h3><ul><li><code>dot tools</code> — แสดงรายการเครื่องมือ CLI ทดแทนที่รวมมาและสถานะ.</li><li><code>dot new</code> — สร้างไฟล์นามแฝงหรือฟังก์ชันใหม่.</li><li><code>dot sandbox</code> — เปิด Shell แซนด์บ็อกซ์แบบใช้แล้วทิ้ง.</li><li><code>dot keys</code> — แสดงการผูกปุ่มปัจจุบัน.</li><li><code>dot learn</code> — เริ่มบทเรียนแบบโต้ตอบ.</li></ul><h3 id="เมตา" tabindex="-1">เมตา <a class="header-anchor" href="#เมตา" aria-label="Permalink to &quot;เมตา&quot;">​</a></h3><ul><li><code>dot upgrade</code> — อัปเกรด Dotfiles เป็นเวอร์ชันล่าสุด.</li><li><code>dot packages</code> — แสดงรายการแพ็คเกจที่ติดตั้งซึ่งจัดการโดย Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — แสดงข้อมูลเวอร์ชันหรือการใช้งาน</li></ul>',28)])])}const b=o(d,[["render",t]]);export{u as __pageData,b as default};
